Add-Content -Path 'd:\IncoziProject\Incozi\style.css' -Value '

/* Quick Links Grid */
.quick-links-grid {
    display: grid;
    grid-template-columns: repeat(auto-fit, minmax(250px, 1fr));
    gap: 2rem;
    margin-top: 4rem;
}

.quick-card {
    background: #fff;
    padding: 2rem;
    border-radius: 12px;
    border: 1px solid var(--bg-300);
    box-shadow: 0 4px 6px rgba(0,0,0,0.05); /* very light shadow */
    display: flex;
    flex-direction: column;
    align-items: flex-start; /* Left align like screenshot */
    text-align: left;
    transition: transform 0.2s, box-shadow 0.2s;
}

.quick-card:hover {
    transform: translateY(-5px);
    box-shadow: 0 10px 20px rgba(0,0,0,0.1);
}

.quick-icon {
    font-size: 2rem;
    color: var(--accent-200); /* Icon color from screenshot */
    background: var(--primary-100); /* Light background for icon */
    width: 50px;
    height: 50px;
    border-radius: 8px; /* Rounded square shape */
    display: flex;
    align-items: center;
    justify-content: center;
    margin-bottom: 1.5rem;
}
.quick-icon i {
    font-size: 1.5rem;
}

.quick-card h3 {
    font-size: 1.25rem;
    margin-bottom: 1rem;
    color: var(--text-100); /* Dark text for title */
}

.quick-card p {
    font-size: 0.95rem;
    color: var(--text-200);
    line-height: 1.6;
    margin-bottom: 2rem;
    flex-grow: 1; /* Push button to bottom */
}

.btn-quick {
    display: inline-block;
    padding: 0.75rem 1.5rem;
    background: var(--bg-200); /* Light beige/grey background like screenshot */
    color: var(--text-100);
    border-radius: 99px;
    font-weight: 600;
    text-decoration: none;
    transition: background 0.2s;
    width: 100%;
    text-align: center;
}

.btn-quick:hover {
    background: var(--bg-300); /* Slightly darker on hover */
}
/* Specific button override for "Start your US business" to match screenshot green */
.quick-card:first-child .btn-quick {
    background: var(--success);
    color: #fff;
}
.quick-card:first-child .btn-quick:hover {
    background: #3ac16e; 
}
'

