Add-Content -Path 'd:\IncoziProject\Incozi\style.css' -Value '

/* Process / Path Section */
.process-section {
    padding: 6rem 1.5rem;
    background: #fff;
    text-align: center; /* Center the section title */
}

.process-steps {
    display: flex;
    justify-content: space-between;
    align-items: flex-start; /* Align tops */
    gap: 1.5rem;
    max-width: 1100px;
    margin: 4rem auto 0;
}

.process-step {
    flex: 1;
    display: flex;
    flex-direction: column;
    align-items: flex-start; /* Left align content */
    text-align: left;
}

.step-number {
    display: inline-flex;
    align-items: center;
    justify-content: center;
    width: 40px;
    height: 40px;
    background: var(--bg-200);
    color: var(--accent-200);
    font-weight: 700;
    border-radius: 8px; /* Rounded square */
    margin-bottom: 1.5rem;
    font-size: 1.1rem;
}
/* Colorful backgrounds for numbers */
.process-step:nth-of-type(1) .step-number { background: #ede9fe; color: #7c3aed; }
.process-step:nth-of-type(2) .step-number { background: #e0e7ff; color: #4338ca; }
.process-step:nth-of-type(3) .step-number { background: #dbeafe; color: #1d4ed8; }

.process-step h3 {
    font-size: 1.25rem;
    margin-bottom: 0.75rem;
    color: var(--text-100);
}

.process-step p {
    font-size: 1rem;
    color: var(--text-200);
    line-height: 1.6;
}

.process-arrow {
    display: flex;
    align-items: center;
    justify-content: center;
    padding-top: 10px; /* Align with top part of content approximately */
    color: var(--text-200);
    opacity: 0.5;
    font-size: 1rem;
    width: 60px; /* fixed width for spacing */
    flex-shrink: 0;
}

@media (max-width: 768px) {
    .process-steps {
        flex-direction: column;
        align-items: center;
        gap: 2rem;
    }
    .process-step {
        align-items: center;
        text-align: center;
        max-width: 100%;
    }
    .process-arrow {
        transform: rotate(90deg);
        width: auto;
        padding: 0;
        margin: 0.5rem 0;
    }
}
'

Add-Content -Path 'd:\IncoziProject\Incozi\style.css' -Value '

/* Cart Badge Styling */
.cart-badge {
    position: absolute;
    top: -5px;
    right: -8px;
    background-color: var(--badge-bg, #ef4444);
    color: #fff;
    font-size: 0.7rem;
    font-weight: 700;
    min-width: 18px;
    height: 18px;
    border-radius: 9px;
    display: flex;
    align-items: center;
    justify-content: center;
    padding: 0 4px;
    border: 2px solid #fff;
    z-index: 10;
}

/* Ensure cart links can position the badge */
a[href*="cart.html"] {
    position: relative;
    /* Ensure no overflow hidden clips the badge */
    overflow: visible; 
}

/* Adjustments for specific contexts if needed */
.sidebar-link-item .cart-badge {
    top: 50%;
    right: 1.5rem;
    transform: translateY(-50%);
    border: none; /* No white border needed on gray background usually, but kept consistent */
}
'

