Add-Content -Path 'd:\IncoziProject\Incozi\style.css' -Value '

/* Unified Header Styles (Persistent Hamburger) */
.persistent-toggle {
    background: none; 
    border: none; 
    font-size: 1.5rem; 
    cursor: pointer; 
    color: var(--text-100);
    display: block !important; /* Force visible on all screens */
    margin-left: 1.5rem;
}

/* Ensure Nav is visible on desktop */
@media (min-width: 769px) {
    .main-nav { display: block !important; }
}

/* On mobile, nav list is hidden, handled by sidebar */
@media (max-width: 768px) {
    .main-nav { display: none !important; }
}
